12	# Carousel
13	
14	`Carousel` presents a sequence of slides with previous/next buttons, dot indicators, keyboard arrow keys, touch/pointer swipe with momentum, and optional auto-play. Supports looping navigation, fractional slides-per-view, configurable alignment, and full WAI-ARIA carousel pattern compliance.
15	
16	## 1. State Machine
17	
18	### 1.1 States
19	
20	```rust
21	#[derive(Clone, Copy, Debug, PartialEq, Eq, Default)]
22	pub enum State {
23	    /// No animation or auto-play in progress.
24	    #[default]
25	    Idle,
26	    /// Auto-play timer is running.
27	    AutoPlaying,
28	    /// A slide transition animation is in progress.
29	    Transitioning,
30	}
31	```
32	
33	### 1.2 Events
34	
35	```rust
36	#[derive(Clone, Copy, Debug, PartialEq)]
37	pub enum Event {
38	    /// Navigate to a specific slide by index.
39	    GoToSlide { index: usize },
40	    /// Navigate to the next slide.
41	    GoToNext,
42	    /// Navigate to the previous slide.
43	    GoToPrev,
44	    /// Start the auto-play timer.
45	    AutoPlayStart,
46	    /// Permanently stop auto-play.
47	    AutoPlayStop,
48	    /// Auto-play timer fired; advance one slide.
49	    AutoPlayTick,
50	    /// Temporarily pause auto-play (hover/focus).
51	    AutoPlayPause,
52	    /// Resume auto-play after pause.
53	    AutoPlayResume,
54	    /// The CSS transition animation completed.
55	    TransitionEnd,
56	    /// Pointer down on the viewport (drag start).
57	    PointerDown { pos: f64, timestamp: f64 },
58	    /// Pointer moved during drag.
59	    PointerMove { pos: f64, timestamp: f64 },
60	    /// Pointer released (drag end).
61	    PointerUp,
62	    /// Pointer cancelled (drag abort).
63	    PointerCancel,
64	    /// A slide received focus.
65	    FocusSlide { index: usize },
66	    /// Focus left the carousel.
67	    Blur,
68	}
69	```
70	
71	### 1.3 Context
72	
73	```rust
74	use crate::{Bindable, Duration};
75	use ars_i18n::Orientation;
76	
77	/// Slide alignment within the viewport.
78	#[derive(Clone, Debug, Copy, PartialEq, Eq, Default)]
79	pub enum SlideAlignment {
80	    #[default]
81	    Start,
82	    Center,
83	    End,
84	}
85	
86	/// Auto-play configuration.
87	#[derive(Clone, Debug, PartialEq)]
88	pub struct AutoPlayOptions {
89	    /// Interval between automatic slide advances.
90	    pub interval: Duration,
91	    /// Whether manual interaction permanently stops auto-play.
92	    pub stop_on_interaction: bool,
93	    /// Whether keyboard focus within the carousel pauses auto-play.
94	    pub pause_on_focus: bool,
95	    /// Whether pointer hover over the carousel pauses auto-play.
96	    pub pause_on_hover: bool,
97	}
98	
99	impl Default for AutoPlayOptions {
100	    fn default() -> Self {
101	        AutoPlayOptions {
102	            interval: Duration::from_millis(4000),
103	            stop_on_interaction: true,
104	            pause_on_focus: true,
105	            pause_on_hover: true,
106	        }
107	    }
108	}
109	
110	/// Runtime context for the Carousel state machine.
111	#[derive(Clone, Debug, PartialEq)]
112	pub struct Context {
113	    /// Current slide index (controlled/uncontrolled).
114	    pub index: Bindable<usize>,
115	    /// Total number of slides.
116	    pub slide_count: NonZero<usize>,
117	    /// Whether navigation wraps around.
118	    pub loop_nav: bool,
119	    /// Auto-play configuration. `None` disables auto-play.
120	    pub auto_play: Option<AutoPlayOptions>,
121	    /// Whether auto-play has been permanently stopped by user interaction.
122	    pub auto_play_stopped: bool,
123	    /// Whether auto-play is temporarily paused (hover/focus).
124	    pub auto_play_paused: bool,
125	    /// Gap between slides in pixels.
126	    pub spacing: f64,
127	    /// Number of slides visible at once (fractional supported).
128	    pub slides_per_view: f64,
129	    /// Number of slides to advance per navigation action. Defaults to `1`.
130	    /// When `slides_per_view > 1`, setting this to match `slides_per_view`
131	    /// provides page-by-page navigation.
132	    pub slides_per_move: usize,
133	    /// Slide alignment within the viewport.
134	    pub align: SlideAlignment,
135	    /// Slide axis.
136	    pub orientation: Orientation,
137	    /// CSS transition duration for slide animations.
138	    pub transition_duration: Duration,
139	    /// Pointer position at drag start. `None` when not dragging.
140	    pub drag_start_pos: Option<f64>,
141	    /// Accumulated drag distance in pixels.
142	    pub drag_delta: f64,
143	    /// Distance threshold (pixels) to trigger a swipe navigation.
144	    pub swipe_threshold: f64,
145	    /// Time-normalized swipe velocity (px/ms). Independent of display refresh rate.
146	    pub swipe_velocity: f64,
147	    /// Timestamp of the last PointerMove event (ms, from `performance.now()`).
148	    pub drag_last_timestamp: Option<f64>,
149	    /// Whether the carousel is right-to-left.
150	    pub is_rtl: bool,
151	    /// Resolved locale for MessageFn calls.
152	    pub locale: Locale,
153	    /// Resolved translatable messages.
154	    pub messages: Messages,
155	    /// Component IDs.
156	    pub ids: ComponentIds,
157	}
158	
159	impl Context {
160	    pub fn current_index(&self) -> usize { *self.index.get() }
161	
162	    /// Clamp or wrap an index according to `loop_nav`.
163	    pub fn clamp_index(&self, i: isize) -> usize {
164	        let n = self.slide_count.get() as isize;
165	        if self.loop_nav {
166	            ((i % n) + n) as usize % self.slide_count.get()
167	        } else {
168	            (i.max(0) as usize).min(self.slide_count.get().saturating_sub(1))
169	        }
170	    }
171	
172	    pub fn can_go_prev(&self) -> bool { self.loop_nav || self.current_index() > 0 }
173	    pub fn can_go_next(&self) -> bool { self.loop_nav || self.current_index() + 1 < self.slide_count.get() }
174	
175	    /// CSS translate percentage for the slide track.
176	    pub fn track_offset_percent(&self, viewport_width: f64) -> f64 {
177	        let idx = self.current_index() as f64;
178	        let per_slide = 100.0 / self.slides_per_view;
179	        let drag_correction = if viewport_width > 0.0 {
180	            (self.drag_delta / viewport_width) * 100.0
181	        } else {
182	            0.0
183	        };
184	        -(idx * per_slide) + drag_correction
185	    }
186	}
187	```
