492	### 1.6 Connect / API
493	
494	```rust
495	#[derive(ComponentPart)]
496	#[scope = "carousel"]
497	pub enum Part {
498	    Root,
499	    Viewport,
500	    ItemGroup,
501	    Item { index: usize },
502	    PrevTrigger,
503	    NextTrigger,
504	    IndicatorGroup,
505	    Indicator { index: usize },
506	    AutoPlayTrigger,
507	    AutoPlayIndicator,
508	    ProgressText,
509	}
510	
511	pub struct Api<'a> {
512	    state: &'a State,
513	    ctx: &'a Context,
514	    props: &'a Props,
515	    send: &'a dyn Fn(Event),
516	}
517	
518	impl<'a> Api<'a> {
519	    pub fn root_attrs(&self) -> AttrMap {
520	        let mut attrs = AttrMap::new();
521	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Root.data_attrs();
522	        attrs.set(scope_attr, scope_val);
523	        attrs.set(part_attr, part_val);
524	        attrs.set(HtmlAttr::Role, "region");
525	        attrs.set(HtmlAttr::Aria(AriaAttr::Label), (self.ctx.messages.carousel_label)(&self.ctx.locale));
526	        attrs.set(HtmlAttr::Aria(AriaAttr::RoleDescription), (self.ctx.messages.role_description)(&self.ctx.locale));
527	        attrs.set(HtmlAttr::Data("ars-state"), match self.state {
528	            State::Idle => "idle",
529	            State::AutoPlaying => "auto-playing",
530	            State::Transitioning => "transitioning",
531	        });
532	        attrs.set(HtmlAttr::Data("ars-orientation"), match self.ctx.orientation {
533	            Orientation::Horizontal => "horizontal",
534	            Orientation::Vertical => "vertical",
535	        });
536	        attrs
537	    }
538	
539	    pub fn viewport_attrs(&self) -> AttrMap {
540	        let mut attrs = AttrMap::new();
541	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::Viewport.data_attrs();
542	        attrs.set(scope_attr, scope_val);
543	        attrs.set(part_attr, part_val);
544	        let touch_action = if self.ctx.orientation == Orientation::Horizontal {
545	            "pan-y"
546	        } else {
547	            "pan-x"
548	        };
549	        attrs.set_style(CssProperty::Overflow, "hidden");
550	        attrs.set_style(CssProperty::TouchAction, touch_action);
551	        attrs
552	    }
553	
554	    pub fn item_group_attrs(&self) -> AttrMap {
555	        let mut attrs = AttrMap::new();
556	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::ItemGroup.data_attrs();
557	        attrs.set(scope_attr, scope_val);
558	        attrs.set(part_attr, part_val);
559	        let live = if self.ctx.auto_play_stopped || self.ctx.auto_play.is_none() {
560	            "polite"
561	        } else {
562	            "off"
563	        };
564	        attrs.set(HtmlAttr::Aria(AriaAttr::Live), live);
565	        attrs
566	    }
567	
568	    pub fn item_attrs(&self, index: usize) -> AttrMap {
569	        let mut attrs = AttrMap::new();
570	        let [(scope_attr, scope_val), (part_attr, part_val)] =
571	            Part::Item { index }.data_attrs();
572	        attrs.set(scope_attr, scope_val);
573	        attrs.set(part_attr, part_val);
574	        let is_current = index == self.ctx.current_index();
575	        let is_hidden = !is_current;
576	        attrs.set(HtmlAttr::Role, "group");
577	        attrs.set(HtmlAttr::Aria(AriaAttr::RoleDescription), (self.ctx.messages.slide_role_description)(&self.ctx.locale));
578	        attrs.set(HtmlAttr::Aria(AriaAttr::Label), (self.ctx.messages.slide_label)(index + 1, self.ctx.slide_count.get(), &self.ctx.locale));
579	        attrs.set(HtmlAttr::Data("ars-index"), index.to_string());
580	        attrs.set_bool(HtmlAttr::Data("ars-active"), is_current);
581	        if is_hidden {
582	            attrs.set(HtmlAttr::Aria(AriaAttr::Hidden), "true");
583	            attrs.set_bool(HtmlAttr::Inert, true);
584	        }
585	        attrs
586	    }
587	
588	    pub fn prev_trigger_attrs(&self) -> AttrMap {
589	        let mut attrs = AttrMap::new();
590	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::PrevTrigger.data_attrs();
591	        attrs.set(scope_attr, scope_val);
592	        attrs.set(part_attr, part_val);
