594	        if !self.ctx.can_go_prev() {
595	            attrs.set(HtmlAttr::Aria(AriaAttr::Disabled), "true");
596	        }
597	        attrs
598	    }
599	
600	    pub fn next_trigger_attrs(&self) -> AttrMap {
601	        let mut attrs = AttrMap::new();
602	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::NextTrigger.data_attrs();
603	        attrs.set(scope_attr, scope_val);
604	        attrs.set(part_attr, part_val);
605	        attrs.set(HtmlAttr::Aria(AriaAttr::Label), (self.ctx.messages.next_label)(&self.ctx.locale));
606	        if !self.ctx.can_go_next() {
607	            attrs.set(HtmlAttr::Aria(AriaAttr::Disabled), "true");
608	        }
609	        attrs
610	    }
611	
612	    pub fn indicator_group_attrs(&self) -> AttrMap {
613	        let mut attrs = AttrMap::new();
614	        let [(scope_attr, scope_val), (part_attr, part_val)] = Part::IndicatorGroup.data_attrs();
615	        attrs.set(scope_attr, scope_val);
616	        attrs.set(part_attr, part_val);
617	        attrs.set(HtmlAttr::Role, "tablist");
