619	    }
620	
621	    pub fn indicator_attrs(&self, index: usize) -> AttrMap {
622	        let mut attrs = AttrMap::new();
623	        let [(scope_attr, scope_val), (part_attr, part_val)] =
624	            Part::Indicator { index }.data_attrs();
