626	        attrs.set(part_attr, part_val);
627	        attrs.set(HtmlAttr::Role, "tab");
628	        attrs.set(HtmlAttr::Aria(AriaAttr::Selected),
629	            if index == self.ctx.current_index() { "true" } else { "false" },
630	        );
631	        attrs
