    type Messages: ComponentMessages + Clone + Default + 'static;
    type Effect: EffectName;
    type Api<'a>: ConnectApi where Self: 'a;

    fn init(props: &Self::Props, env: &Env, messages: &Self::Messages) -> (State, Context);
    fn transition(state: &State, event: &Event, context: &Context, props: &Props) -> Option<TransitionPlan<Self>>;
    fn connect<'a>(state: &'a State, ctx: &'a Context, props: &'a Props, send: &'a dyn Fn(Event)) -> Api<'a>;
